  data, 
  onShowHistory, 
  onShowPath, 
  getAddressLabel, 
  allRawData,
  currentPage,
  totalPages,
  totalFilteredCount,
  onPageChange,
  isPathLoading,
  loadingAddress
}) => {
  const getAmountByAddress = (addr: string) => {
    const found = allRawData.find(d => d.address.toLowerCase() === addr.toLowerCase());
